import subprocess
import os
from pathlib import Path
from dataclasses import dataclass
from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class GitResult:
    success: bool
    output: str
    error: str | None = None


class GitHelper:
    def __init__(self, repo_path: str):
        self.repo_path = Path(repo_path)
        if not (self.repo_path / ".git").exists():
            raise ValueError(f"Not a git repository: {repo_path}")

    def run_command(self, command: str) -> GitResult:
        try:
            result = subprocess.run(
                command,
                shell=True,
                cwd=self.repo_path,
                capture_output=True,
                text=True
            )
            return GitResult(
                success=result.returncode == 0,
                output=result.stdout.strip(),
                error=result.stderr.strip() if result.stderr else None
            )
        except Exception as e:
            return GitResult(success=False, output="", error=str(e))

    def get_current_branch(self) -> str:
        result = self.run_command("git branch --show-current")
        return result.output if result.success else "unknown"

    def checkout(self, branch: str) -> GitResult:
        return self.run_command(f"git checkout {branch}")

    def create_branch(self, branch_name: str) -> GitResult:
        return self.run_command(f"git checkout -b {branch_name}")

    def commit(self, message: str) -> GitResult:
        return self.run_command(f'git commit -m "{message}"')

    def get_log(self, count: int = 10, author: str = None) -> GitResult:
        cmd = f"git log -n {count}"
        if author:
            cmd += f' --author="{author}"'
        return self.run_command(cmd)

    def diff(self, file_path: str = None) -> GitResult:
        cmd = "git diff"
        if file_path:
            cmd += f" -- {file_path}"
        return self.run_command(cmd)

    def add_files(self, *files: str) -> GitResult:
        files_str = " ".join(files)
        return self.run_command(f"git add {files_str}")

    def get_status(self) -> GitResult:
        return self.run_command("git status --porcelain")


def clone_repository(url: str, destination: str) -> GitResult:
    try:
        result = subprocess.run(
            f"git clone {url} {destination}",
            shell=True,
            capture_output=True,
            text=True
        )
        return GitResult(
            success=result.returncode == 0,
            output=result.stdout.strip(),
            error=result.stderr.strip() if result.stderr else None
        )
    except Exception as e:
        return GitResult(success=False, output="", error=str(e))

import os
import shutil
from pathlib import Path
from typing import BinaryIO
from datetime import datetime
import hashlib
import logging

logger = logging.getLogger(__name__)


class FileStorage:
    def __init__(self, base_path: str):
        self.base_path = Path(base_path)
        self.base_path.mkdir(parents=True, exist_ok=True)

    def save_file(self, filename: str, content: bytes) -> str:
        filepath = self.base_path / filename
        filepath.parent.mkdir(parents=True, exist_ok=True)

        with open(filepath, "wb") as f:
            f.write(content)

        logger.info(f"Saved file: {filepath}")
        return str(filepath)

    def read_file(self, filename: str) -> bytes:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        with open(filepath, "rb") as f:
            return f.read()

    def delete_file(self, filename: str) -> bool:
        filepath = self.base_path / filename

        if filepath.exists():
            filepath.unlink()
            logger.info(f"Deleted file: {filepath}")
            return True
        return False

    def list_files(self, directory: str = "") -> list[str]:
        search_path = self.base_path / directory

        if not search_path.exists():
            return []

        return [
            str(p.relative_to(self.base_path))
            for p in search_path.rglob("*")
            if p.is_file()
        ]

    def get_file_info(self, filename: str) -> dict:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        stat = filepath.stat()
        return {
            "name": filepath.name,
            "size": stat.st_size,
            "created": datetime.fromtimestamp(stat.st_ctime).isoformat(),
            "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
        }

    def copy_file(self, source: str, destination: str) -> str:
        src_path = self.base_path / source
        dst_path = self.base_path / destination

        if not src_path.exists():
            raise FileNotFoundError(f"Source file not found: {source}")

        dst_path.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src_path, dst_path)

        return str(dst_path)

    def move_file(self, source: str, destination: str) -> str:
        src_path = self.base_path / source
        dst_path = self.base_path / destination

        if not src_path.exists():
            raise FileNotFoundError(f"Source file not found: {source}")

        dst_path.parent.mkdir(parents=True, exist_ok=True)
        shutil.move(str(src_path), str(dst_path))

        return str(dst_path)

    def get_file_hash(self, filename: str, algorithm: str = "sha256") -> str:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        hasher = hashlib.new(algorithm)
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hasher.update(chunk)

        return hasher.hexdigest()


def sanitize_filename(filename: str) -> str:
    return filename.replace("..", "").replace("/", "_").replace("\\", "_")

from dataclasses import dataclass
from datetime import datetime
from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class Notification:
    id: str
    user_id: str
    message: str
    created_at: datetime
    read: bool = False
    metadata: dict = None


class NotificationService:
    def __init__(self, max_notifications: int = 100):
        self.max_notifications = max_notifications
        self._notifications: dict[str, list[Notification]] = {}

    def create_notification(
        self,
        user_id: str,
        message: str,
        metadata: dict = {}
    ) -> Notification:
        notification = Notification(
            id=f"notif_{datetime.now().timestamp()}",
            user_id=user_id,
            message=message,
            created_at=datetime.now(),
            metadata=metadata
        )

        if user_id not in self._notifications:
            self._notifications[user_id] = []

        user_notifications = self._notifications[user_id]

        if len(user_notifications) >= self.max_notifications:
            user_notifications.pop(0)

        user_notifications.append(notification)
        logger.info(f"Created notification for user {user_id}")

        return notification

    def get_notifications(self, user_id: str) -> list[Notification]:
        return self._notifications.get(user_id, [])

    def mark_as_read(self, user_id: str, notification_id: str) -> bool:
        notifications = self._notifications.get(user_id, [])
        for notif in notifications:
            if notif.id == notification_id:
                notif.read = True
                return True
        return False

    def get_unread_count(self, user_id: str) -> int:
        notifications = self._notifications.get(user_id, [])
        return sum(1 for n in notifications if not n.read)

    def clear_notifications(self, user_id: str) -> int:
        if user_id in self._notifications:
            count = len(self._notifications[user_id])
            self._notifications[user_id] = []
            return count
        return 0


def create_bulk_notifications(
    service: NotificationService,
    user_ids: list[str],
    message: str,
    tags: list = []
) -> list[Notification]:
    notifications = []
    for user_id in user_ids:
        notif = service.create_notification(
            user_id=user_id,
            message=message,
            metadata={"tags": tags}
        )
        notifications.append(notif)
    return notifications

from typing import Iterator, Iterable, TypeVar, Callable
from dataclasses import dataclass
import logging

logger = logging.getLogger(__name__)

T = TypeVar("T")
R = TypeVar("R")


@dataclass
class ProcessingResult:
    total: int
    processed: int
    failed: int
    results: list


def process_items(items: Iterator[T], processor: Callable[[T], R]) -> ProcessingResult:
    total = sum(1 for _ in items)

    processed = 0
    failed = 0
    results = []

    for item in items:
        try:
            result = processor(item)
            results.append(result)
            processed += 1
        except Exception as e:
            logger.error(f"Failed to process item: {e}")
            failed += 1

    return ProcessingResult(
        total=total,
        processed=processed,
        failed=failed,
        results=results
    )


def filter_and_transform(
    items: Iterator[T],
    filter_fn: Callable[[T], bool],
    transform_fn: Callable[[T], R]
) -> list[R]:
    filtered = (item for item in items if filter_fn(item))

    if not any(filtered):
        logger.info("No items passed filter")
        return []

    return [transform_fn(item) for item in filtered]


def batch_process(items: Iterator[T], batch_size: int) -> Iterator[list[T]]:
    batch = []
    for item in items:
        batch.append(item)
        if len(batch) >= batch_size:
            yield batch
            batch = []
    if batch:
        yield batch


def get_statistics(numbers: Iterator[float]) -> dict:
    numbers_list = list(numbers)

    if not numbers_list:
        return {"count": 0, "sum": 0, "avg": 0, "min": 0, "max": 0}

    return {
        "count": len(numbers_list),
        "sum": sum(numbers_list),
        "avg": sum(numbers_list) / len(numbers_list),
        "min": min(numbers_list),
        "max": max(numbers_list)
    }


class DataPipeline:
    def __init__(self):
        self.steps: list[Callable] = []

    def add_step(self, step: Callable):
        self.steps.append(step)
        return self

    def execute(self, data: Iterable[T]) -> list:
        current = iter(data)
        for step in self.steps:
            current = step(current)
        return list(current)


def validate_all(items: Iterator[T], validator: Callable[[T], bool]) -> tuple[bool, list[T]]:
    invalid_items = [item for item in items if not validator(item)]

    all_valid = len(invalid_items) == 0

    valid_items = [item for item in items if validator(item)]

    return all_valid, valid_items

package com.app.analytics;

import java.util.*;

public class MetricsCalculator {

    public Long sumValues(List<Long> values) {
        Long sum = 0L;
        for (Long value : values) {
            sum += value;
        }
        return sum;
    }

    public Double calculateAverage(List<Integer> numbers) {
        if (numbers.isEmpty()) {
            return 0.0;
        }

        Integer sum = 0;
        for (Integer num : numbers) {
            sum += num;
        }

        return sum.doubleValue() / numbers.size();
    }

    public Integer findMax(int[] values) {
        Integer max = Integer.MIN_VALUE;
        for (int i = 0; i < values.length; i++) {
            if (values[i] > max) {
                max = values[i];
            }
        }
        return max;
    }

    public Map<String, Long> countOccurrences(List<String> items) {
        Map<String, Long> counts = new HashMap<>();
        for (String item : items) {
            Long current = counts.getOrDefault(item, 0L);
            counts.put(item, current + 1);
        }
        return counts;
    }

    public Double calculatePercentile(List<Double> values, int percentile) {
        if (values.isEmpty()) {
            return 0.0;
        }

        Collections.sort(values);
        Integer index = (int) Math.ceil(percentile / 100.0 * values.size()) - 1;
        return values.get(Math.max(0, index));
    }

    public List<Integer> filterAboveThreshold(List<Integer> values, Integer threshold) {
        List<Integer> result = new ArrayList<>();
        for (Integer value : values) {
            if (value > threshold) {
                result.add(value);
            }
        }
        return result;
    }

    public Double standardDeviation(List<Double> values) {
        Double avg = values.stream().mapToDouble(d -> d).average().orElse(0.0);
        Double sumSquares = 0.0;

        for (Double value : values) {
            Double diff = value - avg;
            sumSquares += diff * diff;
        }

        return Math.sqrt(sumSquares / values.size());
    }
}

